nome = _items[0]["json"].get("nome") or ""
email = _items[0]["json"].get("email") or ""
oggetto = _items[0]["json"].get("oggetto") or ""
score = _items[0]["json"].get("score") or 0
note = _items[0]["json"].get("note") or ""

def pulisci_nome(nome):
    return nome.strip().lower()

def pulisci_email(email):
    return email.split("@")[1].lower()

def pulisci_numero(numero):
    return round(numero, 2)

def maiuscola_iniziale(testo):
    return testo.capitalize()

def rimuovi_spazi(testo):
    return testo.replace(" ", "")

def conta_caratteri(testo):
    return len(testo)

def testo_vuoto(testo):
    return len(testo) == 0

def unisci_nome(nome, cognome):
    return f"{nome} {cognome}"

def estrai_prefisso_email(email):
    return email.split("@")[0].lower()

def formatta_percentuale(numero):
    return f"{int(numero * 100)}%"

return [{"json": {
    "nome_pulito":        pulisci_nome(nome),
    "dominio":            pulisci_email(email),
    "score_pulito":       pulisci_numero(score),
    "oggetto_pulito":     maiuscola_iniziale(oggetto),
    "caratteri_oggetto":  conta_caratteri(oggetto),
    "note_vuote":         testo_vuoto(note),
    "username":           estrai_prefisso_email(email),
    "percentuale":        formatta_percentuale(score)
}}]
